import React from "react";
import ReactExport from "react-export-excel";

const ExcelFile = ReactExport.ExcelFile;
const ExcelSheet = ReactExport.ExcelFile.ExcelSheet;
const ExcelColumn = ReactExport.ExcelFile.ExcelColumn;

export default function ExcelDownload({ fileName, dataSets }) {
  return (
    <ExcelFile hideElement filename={fileName || "Download"}>
      {dataSets.map((dataset, i) => {
        return (
          <ExcelSheet key={i} data={dataset.rows} name={dataset.sheetName || "Sheet"}>
            {dataset.columns.map((c, j) => {
              return <ExcelColumn key={j} label={c.name} value={c.excelCell ? c.excelCell : c.selector} />;
            })}
          </ExcelSheet>
        );
      })}
    </ExcelFile>
  );
}
